// components/FormRenderer.tsx

import React, {useCallback, useEffect, useMemo, useState} from 'react';
import type {Control, FieldValues, UseFormGetValues} from 'react-hook-form';
import type {GroupFieldConfigs, IFormElement} from '@lmb-it/kitsconcerto-types';
import {FieldWrapper} from '../layout/FieldWrapper';
import {KeyboardNavContext, useKeyboardNavProvider} from '../../../../../Hooks/useKeyboardNavigation';

// Import all your "dumb" field components
import {
    Checkboxes,
    ColorPicker,
    ContainerElement,
    DateField,
    FileUploader,
    Group,
    InputNumber,
    InputText,
    ListBox,
    Location,
    NormalSelect,
    ObjectElement,
    Password,
    Phone,
    Radios,
    Select,
    Switch,
    TagsSelect,
    Textarea,
    TreeSelect
} from '../fields';
import {Grid} from "../../../../Molecules";
import {GridItem} from '@lmb-it/kitsconcertomobile'
import type {IStyleClasses} from "@lmb-it/kitsconcerto-types";

// ... import all other field components

interface FormRendererProps<T extends FieldValues> extends GroupFieldConfigs<T> {
    elements: IFormElement<T>[];
    control: Control<T>;
    getValues: UseFormGetValues<T>;
    parentPath?: string; // ✨ Pass down the parent path for nesting
    grid?: IStyleClasses;
    focusedField?: string;
    setFocusedField: React.Dispatch<React.SetStateAction<string>>;
}

export const FormRenderer = <T extends FieldValues>({
                                                        elements,
                                                        control,
                                                        getValues,
                                                        groupField,
                                                        grid = {},
                                                        parentPath = '',
                                                        focusedField, setFocusedField
                                                    }: FormRendererProps<T>) => {

    const [gridItemProps, setGridItemProps] = useState<Record<string, string>>({})

    // --- Keyboard navigation ---
    const TEXT_TYPES = ['Text', 'Email', 'Number', 'Password', 'Phone'];
    const textFieldIds = useMemo(() => {
        return elements
            .filter((el) => TEXT_TYPES.includes(el.type))
            .map((el) => `${parentPath}${el.id as string}`);
    }, [elements, parentPath]);

    const keyboardNavCtx = useKeyboardNavProvider();

    useEffect(() => {
        keyboardNavCtx.setElementsOrder(textFieldIds);
    }, [textFieldIds]);

    const getElement = useCallback((elementType: string) => {

        switch (elementType) {

            case 'Email':
            case 'Text':
                return InputText;
            case 'Number':
                return InputNumber;
            case 'Password':
                return Password;
            case 'Location':
                return Location;
            case 'Phone':
                return Phone
            case 'Date':
                return DateField
            case 'ColorPicker':
                return ColorPicker
            case 'Radios':
                return Radios
            case 'Textarea':
                return Textarea
            case 'Image':
            case 'File':
                return FileUploader
            case 'Switch':
                return Switch
            case 'Checkbox':
                return Checkboxes
            case 'Select':
                return NormalSelect
            case 'TreeSelect':
                return TreeSelect
            case 'Tags':
                return TagsSelect
            case 'ListBox':
                return ListBox
            case 'Multiselect':
                return Select
            case 'Group':
                return Group
            case 'Object':
                return ObjectElement
            case 'Container':
                return ContainerElement
            // default:
            //     return <Flex/>;
        }
    }, []);


    return (
        <KeyboardNavContext.Provider value={keyboardNavCtx}>
            <Grid
                columns={12}
                rowGap={10}
                colSpan={12}
                columnGap={10}
                w={"full"}
                m={0}
                position={"relative"}
                {...grid as any}
            >
                {elements.map((element) => {

                    const FieldComponent = getElement(element.type);

                    const elementId = `${parentPath}${element.id as string}`;
                    const resolvedElement = elementId !== element.id ? { ...element, id: elementId } : element;


                    if (!FieldComponent) {
                        console.warn(`No component found for element type: "${resolvedElement.type}"`);
                        return null;
                    }

                    const className = 'col-span-' + (gridItemProps[elementId] ?? '12')

                    return (
                        <GridItem key={elementId} _extra={{
                            className: className
                        }}>
                            <FieldWrapper
                                key={elementId}
                                element={resolvedElement}
                                control={control}
                                grid={grid}
                                groupField={groupField}
                                getValues={getValues}
                                focusedField={focusedField}
                                setFocusedField={setFocusedField}
                                onGridChange={(value) => {
                                    if (value != gridItemProps[elementId]) {
                                        setGridItemProps(prevState => ({
                                            ...prevState,
                                            [elementId]: value
                                        }));
                                    }
                                }}


                            >
                                {(props) => <FieldComponent
                                    groupField={groupField}
                                    element={resolvedElement}
                                    control={control}
                                    getValues={getValues}
                                    focusedField={focusedField}
                                    setFocusedField={setFocusedField}
                                    fieldLogic={props}

                                />}
                            </FieldWrapper>
                        </GridItem>
                    );
                })}
            </Grid>
        </KeyboardNavContext.Provider>
    );
};
